import { jsPDF } from 'jspdf';
import i18next from 'i18next';
import certificateConfig from '../config/certificateTemplates.json';
import QRCode from 'qrcode';

// 导入crypto模块（如果在Node.js环境中）或使用浏览器兼容的哈希函数
// 浏览器兼容的哈希函数
function sha256(str) {
  return crypto.subtle.digest('SHA-256', new TextEncoder().encode(str)).then(hashBuffer => {
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    return hashHex;
  });
}

/**
 * 证书生成服务 - 用于创建可下载的证书PDF
 */
class CertificateGenerator {
  /**
   * 根据证书数据生成PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {Promise<Blob>} 返回PDF Blob
   */
  static generateCertificatePDF(certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 获取当前语言
        const currentLanguage = i18next.language;
        const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

        // 创建PDF文档 (A4横向)
        const doc = new jsPDF({
          orientation: 'landscape',
          unit: 'mm',
          format: 'a4'
        });

        // 设置文档属性
        doc.setProperties({
          title: `${certificate.name} - ${isEnglish && certificate.english_course ? certificate.english_course : certificate.course} Certificate`,
          subject: 'Stratford International University Certificate',
          author: 'Stratford International University',
          keywords: 'certificate, education, diploma, blockchain, verified',
          creator: 'SIU Certificate System'
        });

        // 添加水印
        this.addWatermark(doc);

        // 加载证书SVG作为背景并处理后续操作
        this.loadSVGBackground(doc, certificate).then(async () => {
          // 添加证书详细信息
          this.addCertificateDetails(doc, certificate);

          // 生成区块链验证哈希
          const blockchainHash = await this.generateBlockchainHash(certificate);
          certificate.blockchainHash = blockchainHash;

          // 添加QR码 (用于验证)
          await this.addVerificationQR(doc, certificate);

          // 添加签名图片
          await this.addSignatureImages(doc, certificate);

          // 添加装饰元素和装饰花边
          this.addDecorativeElements(doc);

          // 生成PDF并返回
          const pdfBlob = doc.output('blob');
          resolve(pdfBlob);
        }).catch(error => {
          console.error('加载SVG背景失败:', error);
          reject(error);
        });
      } catch (error) {
        console.error('PDF生成错误:', error);
        reject(error);
      }
    });
  }

  /**
   * 对外公开的下载证书方法 - 修复了removeChild相关错误
   * @param {Object} certificate - 证书数据
   * @returns {Promise<boolean>} 下载是否成功
   */
  static async downloadCertificate(certificate) {
    try {
      // 检查证书对象是否有效
      if (!certificate) {
        console.error('证书对象无效');
        alert('无法下载证书：证书数据无效');
        return false;
      }

      // 检查证书是否有图像路径
      if (!certificate.processedImage && !certificate.image) {
        console.error('证书没有图像路径');
        alert('无法下载证书：没有文件');
        return false;
      }

      // 从内存中获取处理好的SVG
      let svgImage;
      try {
        if (certificate.processedImage && certificate.processedImage.startsWith('blob:')) {
          console.log(`尝试获取处理好的图像: ${certificate.processedImage}`);
          const response = await fetch(certificate.processedImage);
          if (!response.ok) throw new Error(`获取处理图像失败: ${response.status}`);
          svgImage = await response.text();
          console.log('成功获取处理好的图像');
        } else {
          // 如果没有处理好的图像，获取原始SVG并处理
          // 检查图像路径是否正确
          if (!certificate.image) {
            console.error('证书图像路径为空');
            throw new Error('证书图像路径为空');
          }

          // 确保路径以/开头
          const imagePath = certificate.image.startsWith('/') ? certificate.image : `/${certificate.image}`;

          // 构建完整URL
          const baseUrl = window.location.origin;
          const fullImageUrl = `${baseUrl}${imagePath}`;
          console.log(`尝试获取原始图像，路径: ${fullImageUrl}`);
          console.log(`原始图像路径: ${certificate.image}`);
          const response = await fetch(fullImageUrl);
          if (!response.ok) {
            console.error(`获取原始图像失败: ${response.status}，URL: ${fullImageUrl}`);
            throw new Error(`获取原始图像失败: ${response.status}，请检查图像路径是否正确`);
          }
          let svgText = await response.text();
          console.log(`成功获取SVG内容，长度: ${svgText.length}字符`);

          // 检查SVG内容是否有效
          if (!svgText.includes('<svg') || !svgText.includes('</svg>')) {
            console.error('获取的内容不是有效的SVG格式');
            console.log('获取的内容前100个字符:', svgText.substring(0, 100));
            throw new Error('获取的内容不是有效的SVG格式');
          }

          // 替换占位符
          svgText = svgText.replace(/\[RECIPIENT NAME\]/g, certificate.name);
          svgText = svgText.replace(/\[DATE\]/g, certificate.date);
          svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, certificate.certificateId);
          svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, certificate.course);
          svgText = svgText.replace(/\[HASH\]/g, 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase());
          svgImage = svgText;
        }
      } catch (fetchError) {
        console.error('获取证书图像失败:', fetchError);
        alert(`无法下载证书：${fetchError.message}`);
        return false;
      }

      // 检查SVG内容是否有效
      if (!svgImage || svgImage.trim() === '') {
        console.error('SVG内容为空');
        alert('无法下载证书：SVG内容无效');
        return false;
      }

      // 创建blob和URL用于下载
      let blob;
      let svgUrl;
      try {
        blob = new Blob([svgImage], {
          type: 'image/svg+xml'
        });
        svgUrl = URL.createObjectURL(blob);
        if (!svgUrl) throw new Error('创建URL对象失败');
      } catch (blobError) {
        console.error('创建Blob或URL对象失败:', blobError);
        alert(`无法下载证书：${blobError.message}`);
        return false;
      }

      // 为转换创建一个图像元素 - 使用安全的方式创建图像元素
      // 这样可以避免某些浏览器环境中的removeChild错误
      let img;
      try {
        // 首选使用document.createElement
        img = document.createElement('img');
      } catch (e) {
        // 如果DOM操作失败，回退到Image构造函数
        console.warn('DOM操作失败，使用Image构造函数替代:', e);
        img = new Image();
      }

      // 设置图像加载超时
      const imageLoadTimeout = setTimeout(() => {
        console.error('图像加载超时');
        alert('无法下载证书：图像加载超时');
        CertificateGenerator.safeRevokeURL(svgUrl);
        return false;
      }, 10000); // 10秒超时

      // 创建PDF时增加证书高级样式，等待图像加载完成
      return new Promise((resolve, reject) => {
        img.onload = function () {
          clearTimeout(imageLoadTimeout); // 清除超时计时器
          try {
            // 创建一个新的PDF A4大小
            const pdf = new jsPDF({
              orientation: 'landscape',
              unit: 'mm',
              format: 'a4'
            });
            console.log('图像加载成功，开始生成PDF');

            // 添加专业背景
            pdf.setFillColor(252, 252, 250);
            pdf.rect(0, 0, pdf.internal.pageSize.getWidth(), pdf.internal.pageSize.getHeight(), 'F');

            // 添加浅色水印背景
            pdf.setTextColor(240, 240, 245);
            pdf.setFontSize(60);
            pdf.setFont('helvetica', 'bold', 'normal');
            pdf.text('STRATFORD', pdf.internal.pageSize.getWidth() / 2, 70, {
              align: 'center',
              angle: 45,
              opacity: 0.1
            });
            pdf.text('UNIVERSITY', pdf.internal.pageSize.getWidth() / 2, 100, {
              align: 'center',
              angle: 45,
              opacity: 0.1
            });

            // 添加装饰性边框
            const pageWidth = pdf.internal.pageSize.getWidth();
            const pageHeight = pdf.internal.pageSize.getHeight();

            // 绘制金色边框
            pdf.setDrawColor(173, 151, 79); // 金色
            pdf.setLineWidth(1);
            pdf.rect(10, 10, pageWidth - 20, pageHeight - 20, 'S');

            // 绘制第二层边框
            pdf.setDrawColor(0, 48, 135); // 深蓝色
            pdf.setLineWidth(0.5);
            pdf.rect(15, 15, pageWidth - 30, pageHeight - 30, 'S');

            // 计算PDF内的图像尺寸和位置
            const imgWidth = pageWidth - 40;
            const imgHeight = img.height * imgWidth / img.width;
            const x = 20;
            const y = (pageHeight - imgHeight) / 2;

            // 将SVG添加到PDF
            pdf.addImage(img.src, 'SVG', x, y, imgWidth, imgHeight);

            // 添加专业印章 (圆形金色)
            const stampX = pageWidth - 60;
            const stampY = pageHeight - 40;

            // 绘制印章圆圈
            pdf.setDrawColor(173, 151, 79); // 金色
            pdf.setLineWidth(0.7);
            pdf.circle(stampX, stampY, 15, 'S');

            // 绘制内圈
            pdf.setDrawColor(173, 151, 79);
            pdf.setLineWidth(0.3);
            pdf.circle(stampX, stampY, 13, 'S');

            // 添加印章文字
            pdf.setTextColor(173, 151, 79);
            pdf.setFontSize(5);
            pdf.text('OFFICIAL', stampX, stampY - 5, {
              align: 'center'
            });
            pdf.text('UNIVERSITY', stampX, stampY, {
              align: 'center'
            });
            pdf.text('SEAL', stampX, stampY + 5, {
              align: 'center'
            });

            // 底部添加防伪提示
            pdf.setTextColor(100, 100, 100);
            pdf.setFontSize(6);
            pdf.text('This document contains multiple security features and can be verified at verify.stratford-university.edu', pageWidth / 2, pageHeight - 5, {
              align: 'center'
            });

            // 保存PDF
            pdf.save(`${certificate.name}-${certificate.certificateId}.pdf`);

            // 安全清理
            CertificateGenerator.safeRevokeURL(svgUrl);
            resolve(true);
          } catch (error) {
            console.error('Error generating PDF:', error);
            reject(error);
          }
        };
        img.onerror = function (errorEvent) {
          clearTimeout(imageLoadTimeout); // 清除超时计时器
          console.error('证书图像加载失败', errorEvent);

          // 安全释放资源
          CertificateGenerator.safeRevokeURL(svgUrl);

          // 提供详细错误信息
          const errorMsg = '无法加载证书图像，请检查图像文件是否存在且格式正确';
          alert(errorMsg);
          reject(new Error(errorMsg));
        };

        // 添加安全检查，确保在设置src前img元素已准备好
        console.log('开始加载证书图像...');
        setTimeout(() => {
          try {
            img.src = svgUrl;
          } catch (srcError) {
            console.error('设置图像源时出错:', srcError);
            alert(`无法下载证书：${srcError.message}`);
            CertificateGenerator.safeRevokeURL(svgUrl);
            reject(srcError);
          }
        }, 0);
      });
    } catch (error) {
      console.error('Error downloading certificate:', error);

      // 尝试使用备用方法下载证书
      try {
        // 检查错误类型，决定是否使用备用方法
        if (error.toString().includes('removeChild') || error.toString().includes('Node')) {
          console.log('尝试使用备用方法下载证书...');

          // 再次检查图像路径是否存在
          let imageUrl = certificate.processedImage || certificate.image;
          if (!imageUrl) {
            console.error('备用下载失败：没有可用的图像路径');
            alert('无法下载证书：没有文件');
            return false;
          }

          // 确保图像URL是完整的URL
          if (imageUrl.startsWith('/')) {
            const baseUrl = window.location.origin;
            imageUrl = `${baseUrl}${imageUrl}`;
            console.log(`构建完整URL: ${imageUrl}`);
          } else if (!imageUrl.startsWith('http') && !imageUrl.startsWith('blob:')) {
            const baseUrl = window.location.origin;
            imageUrl = `${baseUrl}/${imageUrl}`;
            console.log(`构建完整URL: ${imageUrl}`);
          }

          // 验证图像URL是否可访问
          try {
            console.log(`验证图像URL是否可访问: ${imageUrl}`);
            const checkResponse = await fetch(imageUrl, {
              method: 'HEAD'
            });
            if (!checkResponse.ok) {
              console.error(`备用下载失败：图像不可访问，状态码: ${checkResponse.status}，URL: ${imageUrl}`);

              // 尝试使用备用路径
              if (certificate.image && certificate.image.includes('certificates')) {
                const alternativeUrl = `${window.location.origin}/images/certificates/certificate-template.svg`;
                console.log(`尝试使用备用模板: ${alternativeUrl}`);
                const altResponse = await fetch(alternativeUrl, {
                  method: 'HEAD'
                });
                if (altResponse.ok) {
                  console.log('备用模板可用，使用备用模板');
                  imageUrl = alternativeUrl;
                } else {
                  alert(`无法下载证书：图像文件不存在或无法访问 (${checkResponse.status})`);
                  return false;
                }
              } else {
                alert(`无法下载证书：图像文件不存在或无法访问 (${checkResponse.status})`);
                return false;
              }
            }
          } catch (fetchError) {
            console.error('备用下载失败：图像URL检查失败', fetchError);
            alert(`无法下载证书：${fetchError.message}`);
            return false;
          }

          // 创建一个临时链接元素用于下载
          try {
            console.log(`准备下载图像: ${imageUrl}`);
            const link = document.createElement('a');
            link.href = imageUrl;
            link.download = `${certificate.name}-${certificate.certificateId}.svg`;

            // 模拟点击下载
            document.body.appendChild(link);
            link.click();
            setTimeout(() => {
              document.body.removeChild(link);
            }, 100);

            // 显示成功消息
            alert('证书已下载为SVG格式。如需PDF格式，请稍后再试。');
            return true;
          } catch (downloadError) {
            console.error('下载过程中出错:', downloadError);
            alert(`下载过程中出错: ${downloadError.message}`);
            return false;
          }
        } else {
          // 如果是其他类型的错误，显示具体错误信息
          alert(`无法下载证书：${error.message || '未知错误'}`);
        }
      } catch (backupError) {
        console.error('备用下载方法也失败:', backupError);
        alert(`备用下载方法失败：${backupError.message || '未知错误'}`);
      }
      return false;
    }
  }

  /**
   * 添加水印到PDF文档
   * @param {jsPDF} doc - jsPDF文档对象
   */
  static addWatermark(doc) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    // 设置水印样式
    doc.setTextColor(0, 48, 135); // 深蓝色
    doc.setGState(new doc.GState({
      opacity: 0.04
    }));
    doc.setFontSize(120);
    doc.setFont('helvetica', 'bold');

    // 添加旋转的"SIU"水印
    doc.saveGraphicsState();
    doc.translate(pageWidth / 2, pageHeight / 2);
    doc.rotate(-30);
    doc.text('SIU', 0, 0, {
      align: 'center'
    });
    doc.restoreGraphicsState();

    // 恢复默认样式
    doc.setGState(new doc.GState({
      opacity: 1.0
    }));
  }

