  static async previewCertificate(certificate) {
    try {
      // 检查证书对象是否有效
      if (!certificate) {
        console.error('预览失败：证书对象无效');
        throw new Error('证书数据无效');
      }

      // 如果已经有处理好的图像，直接返回
      if (certificate.processedImage && certificate.processedImage.startsWith('blob:')) {
        console.log(`使用已处理的图像预览: ${certificate.processedImage}`);
        return certificate.processedImage;
      }

      // 检查证书是否有图像路径
      if (!certificate.image) {
        console.error('预览失败：证书没有图像路径');
        throw new Error('没有证书图像');
      }

      // 确保路径以/开头
      const imagePath = certificate.image.startsWith('/') ? certificate.image : `/${certificate.image}`;

      // 构建完整URL
      const baseUrl = window.location.origin;
      const fullImageUrl = `${baseUrl}${imagePath}`;
      console.log(`尝试获取证书图像用于预览，路径: ${fullImageUrl}`);

      // 获取SVG内容
