          if (!altResponse.ok) {
            throw new Error(`获取备用模板失败: ${altResponse.status}`);
          }
          let svgText = await altResponse.text();

          // 替换占位符
          svgText = svgText.replace(/\[RECIPIENT NAME\]/g, certificate.name || '姓名');
          svgText = svgText.replace(/\[DATE\]/g, certificate.date || '日期');
          svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, certificate.certificateId || 'ID');
          svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, certificate.course || '课程');

          // 创建Blob和URL
          const blob = new Blob([svgText], {
            type: 'image/svg+xml'
          });
          const previewUrl = URL.createObjectURL(blob);

          // 保存处理后的图像URL到证书对象
          certificate.processedImage = previewUrl;
          return previewUrl;
        }
        throw new Error(`获取证书图像失败: ${response.status}`);
      }
      let svgText = await response.text();

      // 检查SVG内容是否有效
      if (!svgText.includes('<svg') || !svgText.includes('</svg>')) {
        console.error('获取的内容不是有效的SVG格式');
        throw new Error('获取的内容不是有效的SVG格式');
      }

      // 替换占位符
