        console.log(`使用已处理的图像预览: ${certificate.processedImage}`);
        return certificate.processedImage;
      }

      // 检查证书是否有图像路径
      if (!certificate.image) {
        console.error('预览失败：证书没有图像路径');
        throw new Error('没有证书图像');
      }

      // 确保路径以/开头
      const imagePath = certificate.image.startsWith('/') 
